full_cq_idx = content.find('fullCQData: [', ch2_idx)

# First, I will extract the exact corrupted CQ1 block that contains CQ2 inside it
# CQ1 starts at the first { after fullCQData: [
cq1_start = content.find('{', full_cq_idx)
# We know the corrupted CQ1 ends after CQ2.
# Let's find the string 'id: 2'
cq2_idx = content.find('id: 2,', cq1_start)
# Find the end of CQ2's questions array
cq2_c_label = content.find('label: "c"', cq2_idx)
cq2_c_ans_end = content.find('</div></div>"', cq2_c_label) + len('</div></div>"')
# After this is } (end of part c), ] (end of questions array), } (end of CQ2 object)
cq2_c_brace = content.find('}', cq2_c_ans_end)
cq2_q_bracket = content.find(']', cq2_c_brace)
